@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using BlazorNotifications.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@_notifications.Count</span></h1>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in _notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item">
                <strong>@notification.Message</strong>
                <br />
                <small class="text-muted">@notification.Timestamp.ToString("g")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        // Load initial notifications during prerender AND interactive init.
        // The data is the same both times so the DOM matches (no flicker).
        _notifications = NotificationService.GetAll();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is live and interactive
            // (never during static SSR prerender), so this is safe to start polling.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        var lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;

        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken).ConfigureAwait(false);

            // Simulate server-side generation of new notifications
            NotificationService.GenerateFakeNotification();

            var newItems = NotificationService.GetSince(lastSeenId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                lastSeenId = newItems.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

